#define min(x,y) ( (x) < (y) ? (x) : (y) )

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

extern void read(char* filename, fp* input, int data_rows, int data_cols, int major);
extern long long get_time(void);

static void kernel_ecc(fp timeinst, fp* d_initvalu, fp *d_finavalu, int valu_offset, fp* d_params);
static void kernel_cam(fp timeinst, fp* d_initvalu, fp *d_finavalu, int valu_offset, fp* d_params, int params_offset, fp* d_com, int com_offset, fp Ca);
static void kernel_fin(fp *initvalu, int initvalu_offset_ecc, int initvalu_offset_Dyad, int initvalu_offset_SL, int initvalu_offset_Cyt, fp *parameter, fp *finavalu, fp JCaDyad, fp JCaSL, fp JCaCyt);

static void kernel(int timeinst, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com) {
	int valu_offset;
	int params_offset;
	int com_offset;
	fp CaDyad;
	fp CaSL;
	fp CaCyt;

	valu_offset = 0;
	kernel_ecc(timeinst, d_initvalu, d_finavalu, valu_offset, d_params);

	valu_offset = 46;
	params_offset = 0;
	com_offset = 0;
	CaDyad = d_initvalu[35]*1e3f;
	kernel_cam(timeinst, d_initvalu, d_finavalu, valu_offset, d_params, params_offset, d_com, com_offset, CaDyad);

	valu_offset = 61;
	params_offset = 5;
	com_offset = 1;
	CaSL = d_initvalu[36]*1e3f;
	kernel_cam(timeinst, d_initvalu, d_finavalu, valu_offset, d_params, params_offset, d_com, com_offset, CaSL);

	valu_offset = 76;
	params_offset = 10;
	com_offset = 2;
	CaCyt = d_initvalu[37]*1e3f;
	kernel_cam(timeinst, d_initvalu, d_finavalu, valu_offset, d_params, params_offset, d_com, com_offset, CaCyt);
}

void master(fp timeinst,
					fp* initvalu,
					fp* parameter,
					fp* finavalu,
					fp* com,

					fp* d_initvalu,
					fp* d_finavalu,
					fp* d_params,
					fp* d_com){

	int i;
	int initvalu_offset_ecc;
	int initvalu_offset_Dyad;
	int initvalu_offset_SL;
	int initvalu_offset_Cyt;

	(void)d_initvalu;
	(void)d_finavalu;
	(void)d_params;
	(void)d_com;

	kernel((int)timeinst, initvalu, finavalu, parameter, com);

	initvalu_offset_ecc = 0;
	initvalu_offset_Dyad = 46;
	initvalu_offset_SL = 61;
	initvalu_offset_Cyt = 76;

	kernel_fin(initvalu,
						 initvalu_offset_ecc,
						 initvalu_offset_Dyad,
						 initvalu_offset_SL,
						 initvalu_offset_Cyt,
						 parameter,
						 finavalu,
						 com[0],
						 com[1],
						 com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001f;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001f;
		}
	}
}

