int solver(	fp** y,
					fp* x,
					int xmax,
					fp* params,
					fp* com,

					fp* d_initvalu,
					fp* d_finavalu,
					fp* d_params,
					fp* d_com) {

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0f / 7.0f;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		free(err); free(scale); free(yy);
		return -2;
	}
	if (xmax == xmin){
		free(err); free(scale); free(yy);
		return 0;
	}
	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	for(k=1; k<=xmax; k++) {
		x[k] = k-1;
		h = h_init;
		scale_fina = 1.0f;

		for (j = 0; j < ATTEMPTS; j++) {
			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(x[k], h, y[k-1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0f){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabsf(y[k-1][i]);
				}
				scale[i] = 0.8f * powf( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9f) {
				h = 0.9f;
			}
			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5f * h > (fp)xmax ){
				h = 0.5f * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			free(err); free(scale); free(yy);
			return -1;
		}
	}

	free(err);
	free(scale);
	free(yy);
	return 0;
}

int work(int xmax, int workload){

	long long time0, time1, time2, time3, time4, time5;
	time0 = get_time();

	long long memory;
	int i,j;
	int status;

	fp*** y;
	fp** x;
	fp** params;
	fp* com;

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y = (fp ***) malloc(workload* sizeof(fp **));
	for(i=0; i<workload; i++){
		y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
		for(j=0; j<(1+xmax); j++){
			y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
		}
	}

	x = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		x[i]= (fp *)malloc((1+xmax) *sizeof(fp));
	}

	params = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
	}

	com = (fp*)malloc(3 * sizeof(fp));

	fp* d_initvalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	fp* d_finavalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	fp* d_params = (fp*)malloc(PARAMETERS * sizeof(fp));
	fp* d_com = (fp*)malloc(3 * sizeof(fp));

	time2 = get_time();

	for(i=0; i<workload; i++){
		read("../../data/myocyte/y.txt", y[i][0], EQUATIONS, 1, 0);
	}
	for(i=0; i<workload; i++){
		read("../../data/myocyte/params.txt", params[i], PARAMETERS, 1, 0);
	}

	time3 = get_time();

	for(i=0; i<workload; i++){
		status = solver(y[i], x[i], xmax, params[i], com, d_initvalu, d_finavalu, d_params, d_com);
		if(status !=0){
			printf("STATUS: %d\n", status);
		}
	}

	FILE * pFile;
	pFile = fopen ("output.txt","w");
	if (pFile==NULL){
		fputs ("fopen example",pFile);
		return -1;
	}
	for(i=0; i<workload; i++){
		fprintf(pFile, "WORKLOAD %d:\n", i);
		for(j=0; j<(xmax+1); j++){
			int k;
			fprintf(pFile, "\tTIME %d:\n", j);
			for(k=0; k<EQUATIONS; k++){
				fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
			}
		}
	}
	fclose (pFile);

	time4 = get_time();

	for (i= 0; i< workload; i++){
		for (j= 0; j< (1+xmax); j++){
			free(y[i][j]);
		}
		free(y[i]);
	}
	free(y);

	for (i= 0; i< workload; i++){
		free(x[i]);
	}
	free(x);

	for (i= 0; i< workload; i++){
		free(params[i]);
	}
	free(params);

	time5= get_time();

	free(com);
	free(d_initvalu);
	free(d_finavalu);
	free(d_params);
	free(d_com);

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : RUN COMPUTATION\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time5-time0) / 1000000);

	return 0;
}

