#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#define fp float
#define EQUATIONS 91
#define PARAMETERS 18

extern void read(char* filename, fp* input, int data_rows, int data_cols, int major);
extern long long get_time(void);

extern int solver(fp** y,
                  fp* x,
                  int xmax,
                  fp* params,
                  fp* com,
                  fp* d_initvalu,
                  fp* d_finavalu,
                  fp* d_params,
                  fp* d_com);

int work_2(int xmax, int workload){

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	long memory;
	int i;
	int pointer;

	fp* y;
	long y_mem;

	fp* x;
	long x_mem;

	fp* params;
	int params_mem;

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y_mem = workload * (xmax+1) * EQUATIONS * sizeof(fp);
	y= (fp *) malloc(y_mem);

	x_mem = workload * (xmax+1) * sizeof(fp);
	x= (fp *) malloc(x_mem);

	params_mem = workload * PARAMETERS * sizeof(fp);
	params= (fp *) malloc(params_mem);

	fp* com = (fp*) malloc(workload * 3 * sizeof(fp));
	fp* d_err = (fp*) malloc(workload * EQUATIONS * sizeof(fp));
	fp* d_scale = (fp*) malloc(workload * EQUATIONS * sizeof(fp));
	fp* d_yy = (fp*) malloc(workload * EQUATIONS * sizeof(fp));
	fp* d_initvalu_temp = (fp*) malloc(workload * EQUATIONS * sizeof(fp));
	fp* d_finavalu_temp = (fp*) malloc(workload * 13 * EQUATIONS * sizeof(fp));
	fp* d_params = (fp*) malloc(workload * PARAMETERS * sizeof(fp));

	time2 = get_time();

	for(i=0; i<workload; i++){
		pointer = i * (xmax+1) + 0;
		x[pointer] = 0;
	}

	for(i=0; i<workload; i++){
		pointer = i*((xmax+1)*EQUATIONS);
		read("../../data/myocyte/y.txt", &y[pointer], 91, 1, 0);
	}

	for(i=0; i<workload; i++){
		pointer = i*PARAMETERS;
		read("../../data/myocyte/params.txt", &params[pointer], 18, 1, 0);
	}

	time3 = get_time();

	#pragma omp parallel for schedule(static)
	for(i=0; i<workload; i++){
		int j;
		fp** y_ptr = (fp**)malloc((xmax+1)*sizeof(fp*));
		fp* x_ptr = &x[i*(xmax+1)];
		fp* p_ptr = &params[i*PARAMETERS];
		fp* c_ptr = &com[i*3];
		fp* d_init = &d_initvalu_temp[i*EQUATIONS];
		fp* d_fin = &d_err[i*EQUATIONS];
		fp* d_par = &d_params[i*PARAMETERS];
		fp* d_c = &d_scale[i*EQUATIONS]; /* scratch */
		(void)d_yy;
		(void)d_finavalu_temp;

		for(j=0; j<=xmax; j++){
			y_ptr[j] = &y[i*((xmax+1)*EQUATIONS) + j*EQUATIONS];
		}

		(void)solver(y_ptr, x_ptr, xmax, p_ptr, c_ptr, d_init, d_fin, d_par, d_c);

		free(y_ptr);
	}

	time4 = get_time();

	time5 = get_time();

	free(y);
	free(x);
	free(params);

	free(com);
	free(d_err);
	free(d_scale);
	free(d_yy);
	free(d_initvalu_temp);
	free(d_finavalu_temp);
	free(d_params);

	time6= get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES, COPY TO GPU MEMORY\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : RUN GPU KERNEL\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : COPY GPU DATA TO CPU MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time6-time0) / 1000000);

	return 0;
}
